78: /// Section Header Block magic
79: pub const SHB_MAGIC: u32 = 0x0A0D_0D0A;
80: /// Interface Description Block magic
81: pub const IDB_MAGIC: u32 = 0x0000_0001;
82: /// Simple Packet Block magic
83: pub const SPB_MAGIC: u32 = 0x0000_0003;
84: /// Name Resolution Block magic
85: pub const NRB_MAGIC: u32 = 0x0000_0004;
86: /// Interface Statistic Block magic
87: pub const ISB_MAGIC: u32 = 0x0000_0005;
88: /// Enhanced Packet Block magic
89: pub const EPB_MAGIC: u32 = 0x0000_0006;
90: 
91: /// Systemd Journal Export Block magic
92: pub const SJE_MAGIC: u32 = 0x0000_0009;
93: 
94: /// Decryption Secrets Block magic
95: pub const DSB_MAGIC: u32 = 0x0000_000A;
96: 
97: /// Custom Block magic
98: pub const CB_MAGIC: u32 = 0x0000_0BAD;
99: 
100: /// Do-not-copy Custom Block magic
101: pub const DCB_MAGIC: u32 = 0x4000_0BAD;
102: 
103: /// Byte Order magic
104: pub const BOM_MAGIC: u32 = 0x1A2B_3C4D;
105: 
106: /// Process Information Block magic
107: /// (Apple addition, non standardized)
108: pub const PIB_MAGIC: u32 = 0x8000_0001;
