{"content":"1: use pcap_parser::traits::PcapReaderIterator;
2: use pcap_parser::*;
3: use std::fs::File;
4: use std::io::{BufReader, Read};
5: 
6: static TEST_NTP: &[u8] = include_bytes!("../assets/ntp.pcap");
7: 
8: #[test]
9: fn test_pcap_capture_from_file_and_iter_le() {
10:     let cap = PcapCapture::from_file(TEST_NTP).expect("could not parse file into PcapNGCapture");
11:     for block in cap.iter() {
12:         match block {
13:             PcapBlock::LegacyHeader(_) => (),
14:             PcapBlock::Legacy(b) => {
15:                 assert_eq!(b.caplen, 90);
16:             }
17:             PcapBlock::NG(_) => panic!("unexpected NG data"),
18:         }
19:     }
20: }
21: 
22: #[test]
23: fn test_pcap_reader() {
24:     let path = "assets/ntp.pcap";
25:     let file = File::open(path).unwrap();
26:     let buffered = BufReader::new(file);
27:     let mut num_blocks = 0;
28:     let mut reader = LegacyPcapReader::new(65536, buffered).expect("LegacyPcapReader");
29:     loop {
30:         match reader.next() {
31:             Ok((offset, block)) => {
32:                 num_blocks += 1;
33:                 match block {
34:                     PcapBlockOwned::LegacyHeader(_) => (),
35:                     PcapBlockOwned::Legacy(b) => {
36:                         assert_eq!(b.caplen, 90);
37:                     }
38:                     PcapBlockOwned::NG(_) => panic!("unexpected NG data"),
39:                 }
40:                 reader.consume(offset);
41:             }
42:             Err(PcapError::Eof) => break,
43:             Err(PcapError::Incomplete(_)) => {
44:                 reader.refill().unwrap();
45:             }
46:             Err(e) => panic!("error while reading: {:?}", e),
47:         }
48:     }
49:     assert_eq!(num_blocks, 13); /* 1 (header) + 12 (data blocks) */
50: }
51: 
52: #[test]
53: fn test_truncated_pcap() {
54:     let path = "assets/ntp.pcap";
55:     let mut file = File::open(path).unwrap();
56:     // truncate pcap
57:     let mut buf = vec![0; 981];
58:     file.read_exact(&mut buf).unwrap();
59:     let mut reader = LegacyPcapReader::new(65536, &buf[..]).expect("LegacyPcapReader");
60:     let mut incomplete_count: u32 = 0;
61:     loop {
62:         match reader.next() {
63:             Ok((offset, _block)) => {
64:                 reader.consume(offset);
65:             }
66:             Err(PcapError::Eof) => unreachable!("should not parse without error"),
67:             Err(PcapError::Incomplete(_)) => {
68:                 reader.refill().unwrap();
69:                 incomplete_count += 1;
70:                 if incomplete_count > 1 << 20 {
71:                     panic!("reader stuck in infinite loop");
72:                 }
73:             }
74:             Err(PcapError::UnexpectedEof) => return,
75:             Err(e) => panic!("error while reading: {:?}", e),
76:         }
77:     }
78: }
