80: #[test]
81: fn test_modified_format() {
82:     let path = "assets/modified-format.pcap";
83:     let file = File::open(path).unwrap();
84:     let buffered = BufReader::new(file);
85:     let mut num_blocks = 0;
86:     let mut reader = LegacyPcapReader::new(65536, buffered).expect("LegacyPcapReader");
87:     loop {
88:         match reader.next() {
89:             Ok((offset, block)) => {
90:                 num_blocks += 1;
91:                 match block {
92:                     PcapBlockOwned::LegacyHeader(_) => (),
93:                     PcapBlockOwned::Legacy(b) => {
94:                         assert_eq!(b.caplen, 98);
95:                     }
96:                     PcapBlockOwned::NG(_) => panic!("unexpected NG data"),
97:                 }
98:                 reader.consume(offset);
99:             }
100:             Err(PcapError::Eof) => break,
101:             Err(PcapError::Incomplete(_)) => {
102:                 reader.refill().unwrap();
103:             }
104:             Err(e) => panic!("error while reading: {:?}", e),
